SELECT a.*, p.name as pet_name, s.name as service_name, u.username as user_name, st.username as staff_name FROM appointment a LEFT JOIN pet_profile p ON a.pet_id = p.id LEFT JOIN service_item s ON a.service_id = s.id LEFT JOIN user u ON a.user_id = u.id LEFT JOIN user st ON a.staff_id = st.id WHERE a.user_id = #{userId}
AND a.status = #{status}
ORDER BY a.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM appointment
WHERE user_id = #{userId}

    AND status = #{status}

SELECT a.*, p.name as pet_name, s.name as service_name, u.username as user_name, st.username as staff_name FROM appointment a LEFT JOIN pet_profile p ON a.pet_id = p.id LEFT JOIN service_item s ON a.service_id = s.id LEFT JOIN user u ON a.user_id = u.id LEFT JOIN user st ON a.staff_id = st.id
AND (a.appointment_no LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}
AND a.appointment_date >= #{startDate}
AND a.appointment_date <= #{endDate}
ORDER BY a.create_time DESC LIMIT #{offset}, #{limit}

